import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"裂地斩","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/裂地斩.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/裂地斩.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/白刃类/裂地斩.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"裂地斩",tabindex:"-1"},[s("裂地斩 "),e("a",{class:"header-anchor",href:"#裂地斩","aria-label":'Permalink to "裂地斩"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="裂地斩-1" tabindex="-1">裂地斩 <a class="header-anchor" href="#裂地斩-1" aria-label="Permalink to &quot;裂地斩&quot;">​</a></h1><p>裂地斩<br> B+2000<br> 前提：刀3 拥有内力池<br> 某个轮回者观曾经年兽活动中年兽攻击动作创作而来，由简单朴素的刀法和技巧组成。</p><p>【地涌】你以一个标准动作将2点内力附着于手中刀刃之上，随后快速一刀挥出形成刃风，对前方15米内敌人进行一次白刃攻击，刃风化为缠绕敌人的锁链，被击中的敌人受到2点不可豁免的纠缠。<br> 【裂地】如果【地涌】命中了至少一个敌人，那么你可以再使用一个标准动作施展裂地——用手中刀刃直直砸落地面对前方45米内的敌人进行一次白刃攻击，这次攻击会对敌人额外附加一次B级击飞，如果是实体地面，那么残余的内力和力量会使地面变成崎岖不平，受到攻击的单位需要进行一次反射豁免，失败则陷入B级别、环境来源的困难地形状态，但破坏力度有限，正常来讲除了个别特殊场景，这个地形在一轮后便自动消失。</p><p>变体：你可以在购买时选择不是刀类，而是某一种近战能够砸下去的武器，比如说棍枪等等又或者是某一种长型的天生武器，比如尾巴，整个手臂等来替换效果，当然选择天武的话白刃攻击被替换为肉搏攻击。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
